{
  "schemaVersion": 3,
  "judgeId": "judge_1",
  "batchIndex": 5,
  "comparisons": [
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "c9_oyster_spat_poles",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7's daily transport loop perfectly matches the 'early results' and 'light reading pace' requirement, whereas c9's oyster farming inherently takes months, forcing a disjointed Ch 1-3 workaround (catching mullet) that distracts from the core mechanism."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "c10_net_modifications",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7's physical struggle (pedaling and pumping) and direct trade of undervalued seafood strongly embodies the 'proactively turning sea knowledge into catches/goods' and 'causal cost' better than c10's shore-based service model."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_01",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7's mechanical ingenuity (bicycle pump aerator) provides a more robust and scalable 30-chapter progression (manual -> battery -> truck) compared to dt_01_concept_01's recipe-based progression, which risks repetition."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_02",
      "winnerId": "c7_live_seafood_transport",
      "reason": "dt_01_concept_02's fish sauce fermentation is too slow for the 'early results' requirement, whereas c7 delivers immediate, daily cash flow and a clear state change within the first 3 chapters."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_03",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 involves active risk-taking, physical labor, and direct market negotiation, fitting the 'going to sea, sorting, preserving' and 'negotiating output' requirements much better than dt_01_concept_03's passive repair shop setup."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_04",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 features a stronger economic conflict (competing with ice trucks, convincing restaurants) and a more unique, era-appropriate mechanism than dt_01_concept_04's seaweed gathering."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_05",
      "winnerId": "c7_live_seafood_transport",
      "reason": "While both are strong, c7's visual of pedaling a bumpy road while manually pumping air perfectly captures the 'hardship paving the way for ability' and provides a more dynamic, action-oriented narrative than building an ice cellar."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_06",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7 creates a massive price multiplier by keeping seafood live, offering a much more satisfying 'getting rich' reward loop than dt_01_concept_06's abstract fuel-saving mechanism."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_07",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7's use of a bicycle pump for manual aeration is a highly creative, period-accurate application of limited tech, making it stand out more than dt_01_concept_07's standard sun-drying process."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_08",
      "winnerId": "c7_live_seafood_transport",
      "reason": "dt_01_concept_08 borders on the forbidden 'future memory as exact coordinates' by relying on knowing where the clams moved, whereas c7 relies entirely on mechanical skill, effort, and market negotiation."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_09",
      "winnerId": "c7_live_seafood_transport",
      "reason": "c7's active transport and logistical challenges on rural roads make for a much more engaging and dynamic read than the extremely tedious and static process of hand-sorting salt in dt_01_concept_09."
    },
    {
      "leftId": "c7_live_seafood_transport",
      "rightId": "dt_01_concept_10",
      "winnerId": "c7_live_seafood_transport",
      "reason": "dt_01_concept_10's eco-tourism is highly anachronistic for late 1980s Vietnam, where basic survival was the priority. c7 is perfectly grounded in the era's economic realities and marketization."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "c9_oyster_spat_poles",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8's night fishing provides an immediate, thrilling daily reward loop that fits the pacing requirements perfectly, unlike c9's slow-growing oysters which require a narrative patch in the first 3 chapters."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "c10_net_modifications",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8 fulfills the 'going to sea' requirement with a highly visual and risky mechanism (modifying a petromax lamp, risking expensive kerosene), making it more adventurous than c10's shore-based net repair."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_01",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8's integration of optics, pressure valves, and the high stakes of burning expensive fuel creates a more compelling and scalable mechanism than dt_01_concept_01's cooking recipes."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_02",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8 delivers immediate, high-value catches within the first 3 chapters, perfectly matching the 'early results' constraint, whereas dt_01_concept_02 struggles with the inherently slow fermentation time of fish sauce."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_03",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8's active exploitation of a new fishing method (light luring) drives a much stronger 'getting rich' narrative and 30-chapter expansion (forming a fleet) than dt_01_concept_03's repair service."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_04",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8 utilizes a brilliant, era-appropriate technological upgrade (gimmicking a petromax lamp) that feels much more impactful and rewarding than dt_01_concept_04's simple seaweed foraging."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_05",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8's mechanism involves direct action on the sea with immediate dramatic tension (wind threatening the lamp glass), making it a more engaging core loop than dt_01_concept_05's passive ice storage."
    },
    {
      "leftId": "c8_light_luring_squid",
      "rightId": "dt_01_concept_06",
      "winnerId": "c8_light_luring_squid",
      "reason": "c8 directly and massively increases yield (catching squid), providing a much more satisfying and tangible reward loop than dt_01_concept_06's indirect benefit of saving fuel."
    }
  ]
}
